steps.script:
var m = tree.current_scene
var sc = m.shooting_controller
if sc.eligible_targets.is_empty():
	return false
var target_id = ""
for tid in sc.eligible_targets.keys():
	target_id = str(tid)
	break
var root = sc.weapon_tree.get_root()
if root == null:
	return false
var child = root.get_first_child()
var first_id = ""
var best_id = ""
var best_range = -1
while child != null:
	var wid = str(child.get_metadata(0))
	if first_id == "":
		first_id = wid
	if child.is_selectable(0):
		var rng = int(RulesEngine.get_weapon_profile(wid).get("range", 0))
		if rng > best_range:
			best_range = rng
			best_id = wid
	child = child.get_next()
if best_id == "" or best_id == first_id:
	return false
sc.pad_select_weapon(best_id)
PadRouter.target_highlight_id = target_id
InputDeviceManager.set_meta("chosen_w", best_id)
InputDeviceManager.set_meta("first_w", first_id)
return str(sc.selected_weapon_id) == best_id
